const printSettingIds=['printTextSize','printFont','printWeight'];
function printScale(){return parseFloat($('printTextSize')?.value)||1}
function printPreset(){const s=printScale();if(s>=1.3)return {maxLevels:16,icon:13.5,gap:7};if(s>=1.15)return {maxLevels:19,icon:12.5,gap:6};if(s<.95)return {maxLevels:25,icon:9.5,gap:4};return {maxLevels:22,icon:11,gap:5}}
function printFontFamily(){return $('printFont')?.value||'Helvetica Neue,Helvetica,Arial,sans-serif'}
function printWeightValue(weight){return $('printWeight')?.value==='bold'?Math.max(700,Number(weight)||400):weight}
function cleanedFileTitle(name){return String(name||'').replace(/\.(csv|xlsx?|xlsm)$/i,'').replace(/[_]+/g,' ').replace(/\s+/g,' ').trim()}
function updateSelectedFileName(name){const el=$('selectedFileName');if(el)el.textContent=name||'No file chosen'}
function savePrintSettings(){printSettingIds.forEach(id=>{const el=$(id);if(el)localStorage.setItem('elevate-'+id,el.value)})}
function restorePrintSettings(){printSettingIds.forEach(id=>{const el=$(id),v=localStorage.getItem('elevate-'+id);if(el&&v!==null)el.value=v})}


function parseCSV(text){
  const rows=[]; let row=[],field='',q=false;
  for(let i=0;i<text.length;i++){
    const c=text[i],n=text[i+1];
    if(q){
      if(c==='"'&&n==='"'){field+='"';i++}
      else if(c==='"')q=false; else field+=c;
    }else{
      if(c==='"')q=true;
      else if(c===','){row.push(field);field=''}
      else if(c==='\n'){row.push(field.replace(/\r$/,''));rows.push(row);row=[];field=''}
      else field+=c;
    }
  }
  if(field.length||row.length){row.push(field);rows.push(row)}
  return rows.filter(r=>r.some(v=>String(v).trim()!==''));
}
function pick(obj,names){
  const keys=Object.keys(obj);
  for(const n of names){
    const k=keys.find(k=>k.trim().toLowerCase()===n.toLowerCase());
    if(k!==undefined)return obj[k];
  }
  return '';
}
function parseCoordinateValue(value){
  if(value===null||value===undefined)return NaN;
  let raw=String(value).trim();
  if(!raw)return NaN;

  // Plain decimal feet (for example: -28.983 or 60).
  const plain=raw.replace(/,/g,'');
  if(/^[-+]?\d+(?:\.\d+)?$/.test(plain))return Number(plain);

  // Normalize common Vectorworks/Excel feet-inch characters and spacing.
  raw=raw
    .replace(/[′’`]/g,"'")
    .replace(/[″“”]/g,'"')
    .replace(/ /g,' ')
    .trim();

  const sign=raw.startsWith('-')?-1:1;
  raw=raw.replace(/^[-+]\s*/,'').trim();

  // Feet and optional inches: 29' 4", 29'-4", 29'4 1/2", 29'.
  const feetMatch=raw.match(/^(\d+(?:\.\d+)?)\s*'\s*(?:-?\s*(.*?))?$/);
  if(feetMatch){
    const feet=Number(feetMatch[1]);
    const inches=parseInchesValue(feetMatch[2]||'0');
    return Number.isFinite(inches)?sign*(feet+inches/12):NaN;
  }

  // Inches only: 6", -1", 4 1/2".
  if(raw.includes('"')){
    const inches=parseInchesValue(raw);
    return Number.isFinite(inches)?sign*(inches/12):NaN;
  }

  return NaN;
}
function parseInchesValue(value){
  let text=String(value??'').replace(/"/g,'').trim();
  if(!text)return 0;
  text=text.replace(/-/g,' ').replace(/\s+/g,' ').trim();
  let total=0;
  for(const part of text.split(' ')){
    if(!part)continue;
    if(part.includes('/')){
      const [n,d]=part.split('/').map(Number);
      if(!Number.isFinite(n)||!Number.isFinite(d)||d===0)return NaN;
      total+=n/d;
    }else{
      const n=Number(part);
      if(!Number.isFinite(n))return NaN;
      total+=n;
    }
  }
  return total;
}
function coordinateFromRow(o,decimalNames,displayNames){
  const decimalValue=parseCoordinateValue(pick(o,decimalNames));
  if(Number.isFinite(decimalValue))return decimalValue;
  return parseCoordinateValue(pick(o,displayNames));
}
function normalize(rows){
  sourceHeaders=rows[0].map(x=>x.trim());
  return rows.slice(1).map((r,i)=>{
    const o={}; rows[0].forEach((h,j)=>o[h]=r[j]??'');
    const id=String(pick(o,['HOIST ID','HOISTID','POINT','POINT ID','POINTID','ID','NUMBER','NUM'])).trim();
    const x=coordinateFromRow(o,
      ['DEC X','DECIMAL X','X DECIMAL','X DEC','DECIMAL X COORDINATE'],
      ['X','X COORDINATE','X LOCATION','X POSITION','X POS','X-COORDINATE']);
    const y=coordinateFromRow(o,
      ['DEC Y','DECIMAL Y','Y DECIMAL','Y DEC','DECIMAL Y COORDINATE'],
      ['Y','Y COORDINATE','Y LOCATION','Y POSITION','Y POS','Y-COORDINATE']);
    if(!id||!Number.isFinite(x)||!Number.isFinite(y))return null;
    return {
      _row:i+2,id,
      type:String(pick(o,['HOIST TYPE','TYPE'])).trim(),
      load:parseFloat(String(pick(o,['TOTAL LOAD ','TOTAL LOAD','LOAD'])).replace(/,/g,''))||0,
      trim:String(pick(o,['TRIM'])).trim(),
      x,y,
      xDisplay:String(pick(o,['X','X COORDINATE','X LOCATION','X POSITION','X POS','X-COORDINATE'])).trim(),
      yDisplay:String(pick(o,['Y','Y COORDINATE','Y LOCATION','Y POSITION','Y POS','Y-COORDINATE'])).trim(),
      cable:String(pick(o,['CONTROL CABLE','CABLE'])).trim()
    }
  }).filter(Boolean);
}
function feetInches(value,stepIn=1){
  const neg=value<0; let inches=Math.abs(value)*12;
  inches=Math.round(inches/stepIn)*stepIn;
  let ft=Math.floor(inches/12); let rem=inches-ft*12;
  if(rem>=12){ft++;rem=0}
  let remText=Number.isInteger(rem)?String(rem):String(rem.toFixed(2)).replace(/0+$/,'').replace(/\.$/,'');
  return `${neg?'-':''}${ft}' - ${remText}"`;
}
function symbolFor(type){
  const kind=planSymbolKind(type);
  if(kind==='one')return '○';
  if(kind==='half')return '△';
  if(kind==='quarter')return '◇';
  if(kind==='two')return '□';
  if(kind==='dh')return '⌖';
  if(kind==='pd')return '⬡';
  if(kind==='eot')return '[';
  return '○';
}

function layoutSymbolMarkup(type){
  const kind=planSymbolKind(type);
  const color=planColor(type);
  const common=`stroke="${color}" stroke-width="2" fill="white" stroke-linecap="square" stroke-linejoin="miter"`;

  if(kind==='one'){
    return `<svg class="rig-symbol" viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="12" cy="12" r="9" ${common}/>
      <line x1="12" y1="3" x2="12" y2="21" stroke="${color}" stroke-width="2"/>
      <line x1="3" y1="12" x2="21" y2="12" stroke="${color}" stroke-width="2"/>
    </svg>`;
  }

  if(kind==='half'){
    return `<svg class="rig-symbol" viewBox="0 0 24 24" aria-hidden="true">
      <polygon points="12,2.5 2.8,21 21.2,21" ${common}/>
      <line x1="12" y1="3.5" x2="12" y2="21" stroke="${color}" stroke-width="2"/>
      <line x1="6.8" y1="12" x2="17.2" y2="12" stroke="${color}" stroke-width="2"/>
    </svg>`;
  }

  if(kind==='quarter'){
    return `<svg class="rig-symbol" viewBox="0 0 24 24" aria-hidden="true">
      <polygon points="12,2.5 21.5,12 12,21.5 2.5,12" ${common}/>
      <line x1="12" y1="2.8" x2="12" y2="21.2" stroke="${color}" stroke-width="2"/>
      <line x1="2.8" y1="12" x2="21.2" y2="12" stroke="${color}" stroke-width="2"/>
    </svg>`;
  }

  if(kind==='two'){
    return `<svg class="rig-symbol" viewBox="0 0 24 24" aria-hidden="true">
      <rect x="3" y="3" width="18" height="18" ${common}/>
      <line x1="12" y1="3" x2="12" y2="21" stroke="${color}" stroke-width="2"/>
      <line x1="3" y1="12" x2="21" y2="12" stroke="${color}" stroke-width="2"/>
    </svg>`;
  }

  return `<span class="rig-symbol-text" style="color:${color}">${symbolFor(type)}</span>`;
}

function transformPoint(p){
  const angle=parseInt($('sheetOrientation')?.value||'0',10);
  let x=p.x,y=p.y;
  if(angle===90)return {...p,tx:y,ty:-x};
  if(angle===180)return {...p,tx:-x,ty:-y};
  if(angle===270)return {...p,tx:-y,ty:x};
  return {...p,tx:x,ty:y};
}
function orientationLabels(){
  const angle=parseInt($('sheetOrientation')?.value||'0',10);
  // Labels describe the vertical center column after rotation.
  if(angle===90)return {positive:'SL',negative:'SR'};
  if(angle===270)return {positive:'SR',negative:'SL'};
  const posDS=$('yOrientation').value==='positive';
  if(angle===180)return posDS?{positive:'US',negative:'DS'}:{positive:'DS',negative:'US'};
  return posDS?{positive:'DS',negative:'US'}:{positive:'US',negative:'DS'};
}

function groupRows(){
  const tol=parseFloat($('tolerance').value||0)/12;
  const transformed=points.map(transformPoint);
  const sorted=[...transformed].sort((a,b)=>b.ty-a.ty);
  const groups=[];
  for(const p of sorted){
    let g=groups.find(g=>Math.abs(g.y-p.ty)<=tol);
    if(!g){g={y:p.ty,points:[]};groups.push(g)}
    g.points.push(p);
    g.y=g.points.reduce((sum,v)=>sum+v.ty,0)/g.points.length;
  }
  const order=$('rowOrder').value==='desc'?-1:1;
  groups.sort((a,b)=>order*(a.y-b.y));
  return groups;
}
function applyCellAlignment(){
  const mode=$('cellAlignment')?.value||'center';
  document.documentElement.style.setProperty('--cell-align',mode);
  document.querySelectorAll('.pointcell,.pointtop,.pointid').forEach(el=>{
    el.style.textAlign=mode;
    if(el.classList.contains('pointtop'))el.style.justifyContent=mode==='center'?'center':'flex-start';
  });
}

let layoutFitMode=localStorage.getItem('elevateLayoutFitMode') || 'fit-width';
let layoutNaturalWidth=1000;
let layoutNaturalHeight=1;
let layoutResizeObserver=null;

const layoutViewport={
  scale:1,
  minScale:.20,
  maxScale:4,
  mode:layoutFitMode,
  padding:16
};

function updateLayoutViewButtons(){
  const map={
    fitLayoutWidth:'fit-width',
    fitLayoutPage:'fit-page',
    actualLayoutSize:'actual'
  };
  Object.entries(map).forEach(([id,mode])=>$(id)?.classList.toggle('active',layoutViewport.mode===mode));
  const zoomLabel=$('layoutZoomValue');
  if(zoomLabel)zoomLabel.textContent=`${Math.round(layoutViewport.scale*100)}%`;
}

function measureLayoutPage(){
  const sheet=$('sheet');
  const header=sheet?.querySelector('.sheet-header');
  const content=$('sheetContent') || sheet?.querySelector('.sheet-content');
  const table=sheet?.querySelector('.markout');
  if(!sheet||!table)return {width:1000,height:1};

  // Measure the unscaled page as a strict vertical document: header first,
  // markout second. This prevents stale transformed geometry from allowing
  // rows to paint through or above the project header.
  const oldTransform=sheet.style.transform;
  sheet.style.transform='none';
  const tableWidth=Math.ceil(table.scrollWidth||table.offsetWidth||0);
  const headerWidth=Math.ceil(header?.scrollWidth||header?.offsetWidth||0);
  const width=Math.max(1,layoutNaturalWidth||0,tableWidth,headerWidth);
  const headerHeight=Math.ceil(header?.offsetHeight||0);
  const contentHeight=Math.ceil(content?.scrollHeight||table.scrollHeight||table.offsetHeight||0);
  const height=Math.max(1,headerHeight+contentHeight);
  sheet.style.transform=oldTransform;
  layoutNaturalWidth=width;
  layoutNaturalHeight=height;
  return {width,height};
}

function applyLayoutViewport({resetScroll=false,preserveCenter=false,anchor=null}={}){
  const preview=$('previewTab');
  const frame=$('layoutScaleFrame');
  const sheet=$('sheet');
  if(!preview||!frame||!sheet)return;

  const {width:pageWidth,height:pageHeight}=measureLayoutPage();
  const styles=getComputedStyle(preview);
  const innerWidth=Math.max(1,preview.clientWidth-(parseFloat(styles.paddingLeft)||0)-(parseFloat(styles.paddingRight)||0));
  const innerHeight=Math.max(1,preview.clientHeight-(parseFloat(styles.paddingTop)||0)-(parseFloat(styles.paddingBottom)||0));
  const pad=layoutViewport.padding;

  const oldScale=layoutViewport.scale||1;
  const oldLeft=parseFloat(sheet.style.left)||0;
  const oldTop=parseFloat(sheet.style.top)||0;
  const oldCenterX=preview.scrollLeft+(preview.clientWidth/2);
  const oldCenterY=preview.scrollTop+(preview.clientHeight/2);
  const pageCenterX=(oldCenterX-oldLeft)/oldScale;
  const pageCenterY=(oldCenterY-oldTop)/oldScale;
  const anchorPageX=anchor ? (preview.scrollLeft+anchor.localX-oldLeft)/oldScale : null;
  const anchorPageY=anchor ? (preview.scrollTop+anchor.localY-oldTop)/oldScale : null;

  if(layoutViewport.mode==='fit-width'){
    layoutViewport.scale=Math.min(1,Math.max(layoutViewport.minScale,(innerWidth-(pad*2))/pageWidth));
  }else if(layoutViewport.mode==='fit-page'){
    layoutViewport.scale=Math.min(1,Math.max(layoutViewport.minScale,Math.min((innerWidth-(pad*2))/pageWidth,(innerHeight-(pad*2))/pageHeight)));
  }else if(layoutViewport.mode==='actual'){
    layoutViewport.scale=1;
  }

  const scale=Math.min(layoutViewport.maxScale,Math.max(layoutViewport.minScale,layoutViewport.scale));
  layoutViewport.scale=scale;
  const scaledWidth=Math.ceil(pageWidth*scale);
  const scaledHeight=Math.ceil(pageHeight*scale);
  const frameWidth=Math.max(innerWidth,scaledWidth+(pad*2));
  const frameHeight=Math.max(innerHeight,scaledHeight+(pad*2));
  const left=Math.max(pad,Math.round((frameWidth-scaledWidth)/2));
  const top=layoutViewport.mode==='fit-page'
    ? Math.max(pad,Math.round((frameHeight-scaledHeight)/2))
    : pad;

  preview.classList.add('viewport-engine-active');
  preview.classList.toggle('fit-width-active',layoutViewport.mode==='fit-width');
  preview.classList.toggle('fit-page-active',layoutViewport.mode==='fit-page');
  preview.classList.toggle('actual-size-active',layoutViewport.mode==='actual');
  preview.style.overflow='auto';

  frame.style.position='relative';
  frame.style.width=`${frameWidth}px`;
  frame.style.height=`${frameHeight}px`;
  frame.style.margin='0';
  frame.style.overflow='visible';

  sheet.style.position='absolute';
  sheet.style.left=`${left}px`;
  sheet.style.top=`${top}px`;
  sheet.style.width=`${pageWidth}px`;
  sheet.style.minWidth=`${pageWidth}px`;
  sheet.style.maxWidth=`${pageWidth}px`;
  sheet.style.transformOrigin='top left';
  sheet.style.transform=`scale(${scale})`;
  sheet.style.margin='0';

  if(resetScroll){
    preview.scrollLeft=Math.max(0,(frameWidth-preview.clientWidth)/2);
    preview.scrollTop=layoutViewport.mode==='fit-page' ? Math.max(0,(frameHeight-preview.clientHeight)/2) : 0;
  }else if(anchor && Number.isFinite(anchorPageX) && Number.isFinite(anchorPageY)){
    preview.scrollLeft=Math.max(0,left+(anchorPageX*scale)-anchor.localX);
    preview.scrollTop=Math.max(0,top+(anchorPageY*scale)-anchor.localY);
  }else if(preserveCenter){
    preview.scrollLeft=Math.max(0,left+(pageCenterX*scale)-(preview.clientWidth/2));
    preview.scrollTop=Math.max(0,top+(pageCenterY*scale)-(preview.clientHeight/2));
  }

  sheet.dataset.viewportScale=String(scale);
  updateLayoutViewButtons();
}

function setLayoutViewMode(mode){
  const allowed=['fit-width','fit-page','actual','custom'];
  layoutViewport.mode=allowed.includes(mode)?mode:'fit-width';
  layoutFitMode=layoutViewport.mode;
  if(mode!=='custom')localStorage.setItem('elevateLayoutFitMode',mode);
  requestAnimationFrame(()=>requestAnimationFrame(()=>applyLayoutViewport({resetScroll:true})));
}

function setLayoutZoom(nextScale,{preserveCenter=true,anchor=null}={}){
  layoutViewport.mode='custom';
  layoutViewport.scale=Math.min(layoutViewport.maxScale,Math.max(layoutViewport.minScale,nextScale));
  requestAnimationFrame(()=>applyLayoutViewport({preserveCenter,anchor}));
}

function zoomLayoutBy(factor,anchor=null){
  setLayoutZoom(layoutViewport.scale*factor,{preserveCenter:!anchor,anchor});
}

function layoutPointerAnchor(event){
  const preview=$('previewTab');
  if(!preview)return null;
  const rect=preview.getBoundingClientRect();
  return {
    localX:Math.max(0,Math.min(preview.clientWidth,event.clientX-rect.left)),
    localY:Math.max(0,Math.min(preview.clientHeight,event.clientY-rect.top))
  };
}

function fitMobileLayoutPreview(){
  if(layoutViewport.mode==='fit-width'||layoutViewport.mode==='fit-page'){
    requestAnimationFrame(()=>applyLayoutViewport({resetScroll:true}));
  }else{
    requestAnimationFrame(()=>applyLayoutViewport());
  }
}

function initLayoutResizeObserver(){
  if(!('ResizeObserver' in window))return;
  layoutResizeObserver?.disconnect();
  let raf=0;
  layoutResizeObserver=new ResizeObserver(()=>{
    cancelAnimationFrame(raf);
    raf=requestAnimationFrame(fitMobileLayoutPreview);
  });
  const preview=$('previewTab');
  const main=document.querySelector('.main');
  const viewport=document.querySelector('.workspace-viewport');
  [preview,main,viewport].filter(Boolean).forEach(el=>layoutResizeObserver.observe(el));
}

function render(){
  $('sheetTitle').textContent=$('projectName').value||'UNTITLED MARKOUT';
  $('heading').textContent=$('projectName').value||'Layout Preview';
  $('exportDate').textContent=fmtDate();
  $('countMeta').textContent=points.length;
  $('pointBadge').textContent=`${points.length} points`;
  const total=points.reduce((s,p)=>s+(Number(p.load)||0),0);
  $('totalLoad').textContent=total?`${Math.round(total).toLocaleString()} lb`:'--- lb';
  const groups=groupRows();
  const screenZeroTol=Math.max(.0001,parseFloat($('tolerance').value||0)/12);
  const leftCols=Math.max(1,...groups.map(g=>g.points.filter(p=>p.tx < -screenZeroTol).length));
  const rightCols=Math.max(1,...groups.map(g=>g.points.filter(p=>p.tx > screenZeroTol).length));
  const body=$('layoutBody'); body.innerHTML='';
  layoutNaturalHeight=1;

  // Keep dense rows readable instead of squeezing every point into the viewport.
  // This only affects the on-screen Layout view; printed pages use their own renderer.
  const SCREEN_POINT_CELL_W=122;
  const SCREEN_CENTER_W=86;
  const SCREEN_SHEET_PADDING=4;
  const screenSheetWidth=(leftCols*SCREEN_POINT_CELL_W)+SCREEN_CENTER_W+(rightCols*SCREEN_POINT_CELL_W)+SCREEN_SHEET_PADDING;
  layoutNaturalWidth=screenSheetWidth;
  const screenSheet=document.querySelector('#previewTab .sheet');
  if(screenSheet){
    screenSheet.style.setProperty('--layout-sheet-width',`${screenSheetWidth}px`);
    screenSheet.style.width=`${screenSheetWidth}px`;
    screenSheet.style.minWidth=`${screenSheetWidth}px`;
  }

  // Explicit widths prevent Chrome from redistributing and squeezing columns.
  const layoutTable=document.querySelector('#previewTab .markout');
  if(layoutTable){
    layoutTable.querySelector('colgroup')?.remove();
    const colgroup=document.createElement('colgroup');
    for(let i=0;i<leftCols;i++){
      const col=document.createElement('col');
      col.style.width=`${SCREEN_POINT_CELL_W}px`;
      colgroup.appendChild(col);
    }
    const centerCol=document.createElement('col');
    centerCol.style.width=`${SCREEN_CENTER_W}px`;
    colgroup.appendChild(centerCol);
    for(let i=0;i<rightCols;i++){
      const col=document.createElement('col');
      col.style.width=`${SCREEN_POINT_CELL_W}px`;
      colgroup.appendChild(col);
    }
    layoutTable.insertBefore(colgroup,layoutTable.firstChild);
    const exactTableWidth=(leftCols*SCREEN_POINT_CELL_W)+SCREEN_CENTER_W+(rightCols*SCREEN_POINT_CELL_W);
    layoutTable.style.width=`${exactTableWidth}px`;
    layoutTable.style.minWidth=`${exactTableWidth}px`;
    layoutTable.style.maxWidth=`${exactTableWidth}px`;
    if(screenSheet)screenSheet.dataset.datumX=String((leftCols*SCREEN_POINT_CELL_W)+(SCREEN_CENTER_W/2));
  }

  if(!points.length){body.innerHTML='<tr><td style="padding:30px;text-align:center">Import a CSV to generate a markout.</td></tr>';renderData();requestAnimationFrame(()=>applyLayoutViewport({resetScroll:true}));return}
  const step=parseFloat($('precision').value);
  const origin=parseFloat($('originY').value)||0;
  const posDS=$('yOrientation').value==='positive';
  for(const g of groups){
    // Hyperlay-style packing:
    // Left side: blank cells on the OUTSIDE, points packed against centerline.
    // Right side: points packed against centerline, blank cells on the OUTSIDE.
    const zeroTol=Math.max(.0001,parseFloat($('tolerance').value||0)/12);
    const left=g.points.filter(p=>p.tx < -zeroTol).sort((a,b)=>a.tx-b.tx);   // farthest left -> nearest center
    const centerPoints=g.points.filter(p=>Math.abs(p.tx)<=zeroTol).sort((a,b)=>String(a.id).localeCompare(String(b.id)));
    const right=g.points.filter(p=>p.tx > zeroTol).sort((a,b)=>a.tx-b.tx); // nearest center -> farthest right
    const leftCells=[...Array(Math.max(0,leftCols-left.length)).fill(null),...left];
    const rightCells=[...right,...Array(Math.max(0,rightCols-right.length)).fill(null)];

    const tr=document.createElement('tr');
    for(let i=0;i<leftCols;i++)tr.appendChild(pointCell(leftCells[i],step));

    const rel=g.y-origin;
    const labels=orientationLabels();
    const dir=rel>=0?labels.positive:labels.negative;
    const center=document.createElement('td');
    center.className='center';
    if(Math.abs(rel)<=zeroTol)center.classList.add('zero-center');
    const isDatumZero=Math.abs(rel)<=zeroTol;
    const axisMarkup=`<div class="center-axis-label"><small>${isDatumZero?'CENTER':dir}</small><div class="distance">${isDatumZero?feetInches(0,step):feetInches(Math.abs(rel),step)}</div></div>`;
    const centerPointMarkup=centerPoints.length
      ? `<div class="center-point-list">${centerPoints.map(p=>{
          const cable=$('showCable')?.checked && p.cable ? `<div class="cableline">Cable: ${escapeHTML(p.cable)}</div>` : '';
          return `<div class="center-point" title="${escapeHTML(p.id)} | 0' - 0&quot;${p.cable?` | Cable ${escapeHTML(p.cable)}`:''}"><div class="pointtop"><span class="symbol">${layoutSymbolMarkup(p.type)}</span><span>0' - 0&quot;</span></div><div class="pointid">${escapeHTML(p.id)}</div>${cable}</div>`;
        }).join('')}</div>`
      : '';
    center.innerHTML=axisMarkup+centerPointMarkup;
    tr.appendChild(center);

    for(let i=0;i<rightCols;i++)tr.appendChild(pointCell(rightCells[i],step));
    body.appendChild(tr);
  }
  renderData();
  renderPlan();
  applyCellAlignment();
  renderPrintPages();
  requestAnimationFrame(()=>requestAnimationFrame(()=>applyLayoutViewport({resetScroll:true})));
}
function pointCell(p,step){
  const td=document.createElement('td');
  td.className='pointcell'+(!p?' empty':'');
  if(p){
    const cable=$('showCable')?.checked && p.cable
      ? `<div class="cableline">Cable: ${escapeHTML(p.cable)}</div>` : '';
    const measure=feetInches(Math.abs(Number.isFinite(p.tx)?p.tx:p.x),step);
    td.title=`${p.id} | ${measure}${p.cable?` | Cable ${p.cable}`:''}`;
    td.innerHTML=`<div class="pointtop"><span class="symbol">${layoutSymbolMarkup(p.type)}</span><span>${measure}</span></div><div class="pointid">${escapeHTML(p.id)}</div>${cable}`;
  }
  return td;
}
function escapeHTML(s){return String(s).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}
function renderData(){
  const body=$('dataBody');
  body.innerHTML='';

  const coordinateStep=parseFloat($('precision').value)||1;

  points.forEach((p,i)=>{
    const row=document.createElement('div');
    row.className='point-data-row';

    // Preserve the exact X and Y text from the imported CSV.
    // Fall back to generated feet/inches only when the source did not include it.
    const fractionalX=(p.xDisplay||'').trim() || feetInches(p.x,coordinateStep);
    const fractionalY=(p.yDisplay||'').trim() || feetInches(p.y,coordinateStep);

    row.innerHTML=`
      <div><input aria-label="Point" data-i="${i}" data-k="id" value="${escapeHTML(p.id)}"></div>
      <div><input aria-label="Type" data-i="${i}" data-k="type" value="${escapeHTML(p.type)}"></div>
      <div><input aria-label="Load" data-i="${i}" data-k="load" type="number" value="${p.load}"></div>
      <div><input aria-label="Trim" data-i="${i}" data-k="trim" value="${escapeHTML(p.trim)}"></div>
      <div><input class="fractional-coordinate" aria-label="Imported X" value="${escapeHTML(fractionalX)}" readonly tabindex="-1"></div>
      <div><input class="fractional-coordinate" aria-label="Imported Y" value="${escapeHTML(fractionalY)}" readonly tabindex="-1"></div>
      <div><input aria-label="Decimal X" data-i="${i}" data-k="x" type="number" step=".001" value="${p.x}"></div>
      <div><input aria-label="Decimal Y" data-i="${i}" data-k="y" type="number" step=".001" value="${p.y}"></div>
      <div><input aria-label="Cable" data-i="${i}" data-k="cable" value="${escapeHTML(p.cable)}"></div>`;

    body.appendChild(row);
  });
}

function getPlanBounds(){
  if(!points.length)return {minX:-50,maxX:50,minY:-50,maxY:50};
  const tp=points.map(transformPoint);
  let minX=Math.min(...tp.map(p=>p.tx)),maxX=Math.max(...tp.map(p=>p.tx));
  let minY=Math.min(...tp.map(p=>p.ty)),maxY=Math.max(...tp.map(p=>p.ty));
  const padX=Math.max(10,(maxX-minX)*.08),padY=Math.max(10,(maxY-minY)*.08);
  return {minX:minX-padX,maxX:maxX+padX,minY:minY-padY,maxY:maxY+padY};
}
function fitPlan(){
  const b=getPlanBounds();
  planView={x:b.minX,y:b.minY,w:Math.max(20,b.maxX-b.minX),h:Math.max(20,b.maxY-b.minY)};
  renderPlan();
}
function planColor(type){
  const raw=(type||'').trim().toLowerCase();
  const t=raw.replace(/\s+/g,' ');
  if(t.includes('hoist pd')) return '#ffd400';
  if(t==='eot' || t.includes(' eot')) return '#ff4fa3';
  if(t.includes('1/4') || t.includes('¼') || t.includes('.25')) return '#1687ff';
  if(t.includes('1/2') || t.includes('½') || t.includes('.5') || t.includes('half')) return '#58d62e';
  if(t.includes('2 ton') || t==='2t' || t.startsWith('2 ton')) return '#9a42e8';
  if(t.includes('1 ton') || t==='1t' || t.startsWith('1 ton')) return '#e53935';
  return '#6f7b82';
}

function planSymbolKind(type){
  const raw=(type||'').trim().toLowerCase();
  const t=raw.replace(/\s+/g,' ');

  if(t==='eot' || t.includes('eot')) return 'eot';
  if(t.includes('hoist pd') || t==='pd' || t.includes(' pd')) return 'pd';
  if(t==='dh' || t.startsWith('dh') || t.includes('dead hang') || t.includes('dead-hang')) return 'dh';
  if(t.includes('1/4') || t.includes('¼') || t.includes('.25')) return 'quarter';
  if(t.includes('1/2') || t.includes('½') || t.includes('.5') || t.includes('half')) return 'half';
  if(t.includes('2 ton') || t==='2t' || t.startsWith('2 ton')) return 'two';
  if(t.includes('1 ton') || t==='1t' || t.startsWith('1 ton')) return 'one';
  return 'one';
}

function drawPlanSymbol(add,parent,kind,x,y,r,color){
  const stroke=Math.max(.7,r*.28);
  const lineAttrs={
    stroke:color,
    'stroke-width':stroke,
    'stroke-linecap':'square',
    class:'plan-symbol'
  };

  if(kind==='one'){
    add('circle',{
      cx:x,cy:y,r:r,
      fill:'#fff',stroke:color,'stroke-width':stroke,
      class:'plan-symbol plan-symbol-outline point-dot'
    },parent);
    add('line',{x1:x,y1:y-r,x2:x,y2:y+r,...lineAttrs},parent);
    add('line',{x1:x-r,y1:y,x2:x+r,y2:y,...lineAttrs},parent);
    return;
  }

  if(kind==='half'){
    const top=[x,y-r*1.08];
    const left=[x-r*.98,y+r*.84];
    const right=[x+r*.98,y+r*.84];
    add('polygon',{
      points:[top,left,right].map(p=>p.join(',')).join(' '),
      fill:'#fff',stroke:color,'stroke-width':stroke,
      'stroke-linejoin':'miter',
      class:'plan-symbol plan-symbol-outline point-dot'
    },parent);
    add('line',{x1:x,y1:y-r*.98,x2:x,y2:y+r*.84,...lineAttrs},parent);
    add('line',{x1:x-r*.56,y1:y,x2:x+r*.56,y2:y,...lineAttrs},parent);
    return;
  }

  if(kind==='quarter'){
    add('polygon',{
      points:[
        [x,y-r*1.08],
        [x+r*1.08,y],
        [x,y+r*1.08],
        [x-r*1.08,y]
      ].map(p=>p.join(',')).join(' '),
      fill:'#fff',stroke:color,'stroke-width':stroke,
      'stroke-linejoin':'miter',
      class:'plan-symbol plan-symbol-outline point-dot'
    },parent);
    add('line',{x1:x,y1:y-r*1.04,x2:x,y2:y+r*1.04,...lineAttrs},parent);
    add('line',{x1:x-r*1.04,y1:y,x2:x+r*1.04,y2:y,...lineAttrs},parent);
    return;
  }

  if(kind==='two'){
    add('rect',{
      x:x-r,y:y-r,width:r*2,height:r*2,
      fill:'#fff',stroke:color,'stroke-width':stroke,
      class:'plan-symbol plan-symbol-outline point-dot'
    },parent);
    add('line',{x1:x,y1:y-r,x2:x,y2:y+r,...lineAttrs},parent);
    add('line',{x1:x-r,y1:y,x2:x+r,y2:y,...lineAttrs},parent);
    return;
  }

  if(kind==='dh'){
    const arm=r*1.05;
    add('circle',{
      cx:x,cy:y,r:r*.38,fill:'#fff',stroke:color,'stroke-width':stroke,
      class:'plan-symbol plan-symbol-outline point-dot'
    },parent);
    add('line',{x1:x-arm,y1:y,x2:x+arm,y2:y,...lineAttrs},parent);
    add('line',{x1:x,y1:y-arm,x2:x,y2:y+arm,...lineAttrs},parent);
    return;
  }

  if(kind==='pd'){
    const pts=[];
    for(let i=0;i<6;i++){
      const a=-Math.PI/2+i*Math.PI/3;
      pts.push([x+Math.cos(a)*r*1.08,y+Math.sin(a)*r*1.08]);
    }
    add('polygon',{
      points:pts.map(p=>p.join(',')).join(' '),
      fill:'#fff',stroke:color,'stroke-width':stroke,
      class:'plan-symbol plan-symbol-outline point-dot'
    },parent);
    add('circle',{
      cx:x,cy:y,r:r*.28,fill:color,stroke:'none',
      class:'plan-symbol'
    },parent);
    return;
  }

  if(kind==='eot'){
    const txt=add('text',{
      x:x,y:y+r*.5,
      'text-anchor':'middle',
      'font-size':r*2.45,
      'font-weight':'900',
      fill:color,
      class:'plan-symbol point-dot'
    },parent);
    txt.textContent='[';
  }
}
function renderPlan(){
  const svg=$('planSvg');
  if(!svg)return;
  svg.innerHTML='';
  if(!points.length){
    svg.setAttribute('viewBox','0 0 100 100');
    svg.innerHTML='<text x="50" y="50" text-anchor="middle" fill="#677078" font-size="5">Import a CSV to display the plan view.</text>';
    return;
  }
  const invert=$('invertPlanY')?.checked;
  const vb=invert ? `${planView.x} ${-(planView.y+planView.h)} ${planView.w} ${planView.h}` : `${planView.x} ${planView.y} ${planView.w} ${planView.h}`;
  svg.setAttribute('viewBox',vb);
  const ns='http://www.w3.org/2000/svg';
  const add=(tag,attrs,parent=svg)=>{
    const el=document.createElementNS(ns,tag);
    Object.entries(attrs||{}).forEach(([k,v])=>el.setAttribute(k,v));
    parent.appendChild(el);return el;
  };
  const grid=parseFloat($('gridSize')?.value||10);
  const startX=Math.floor(planView.x/grid)*grid,endX=planView.x+planView.w;
  const startY=Math.floor(planView.y/grid)*grid,endY=planView.y+planView.h;
  for(let x=startX;x<=endX;x+=grid){
    add('line',{x1:x,y1:invert?-(planView.y+planView.h):planView.y,x2:x,y2:invert?-planView.y:planView.y+planView.h,class:(Math.abs(x%50)<.001?'grid-line grid-major':'grid-line')});
    const t=add('text',{x:x+0.6,y:invert?-(planView.y+planView.h)+2.5:planView.y+2.5,class:'axis-label','font-size':Math.max(1.8,planView.w/70)});
    t.textContent=`${x}'`;
  }
  for(let y=startY;y<=endY;y+=grid){
    const yy=invert?-y:y;
    add('line',{x1:planView.x,y1:yy,x2:planView.x+planView.w,y2:yy,class:(Math.abs(y%50)<.001?'grid-line grid-major':'grid-line')});
  }
  const origin=parseFloat($('originY').value)||0;
  add('line',{x1:0,y1:invert?-(planView.y+planView.h):planView.y,x2:0,y2:invert?-planView.y:planView.y+planView.h,class:'axis-line'});
  add('line',{x1:planView.x,y1:invert?-origin:origin,x2:planView.x+planView.w,y2:invert?-origin:origin,class:'axis-line'});

  if($('showDatum')?.checked){
    const dx=parseFloat($('datumX').value)||0;
    const dy=parseFloat($('datumY').value)||0;
    const dp=transformPoint({x:dx,y:dy,id:'DATUM',type:'',load:0,trim:'',cable:''});
    const py=invert?-dp.ty:dp.ty;
    const arm=Math.max(4,planView.w/38);
    const ring=Math.max(2.5,planView.w/75);
    add('circle',{cx:dp.tx,cy:py,r:ring,class:'datum-ring'});
    add('line',{x1:dp.tx-arm,y1:py,x2:dp.tx+arm,y2:py,class:'datum-outer'});
    add('line',{x1:dp.tx,y1:py-arm,x2:dp.tx,y2:py+arm,class:'datum-outer'});
    add('line',{x1:dp.tx-arm,y1:py,x2:dp.tx+arm,y2:py,class:'datum-inner'});
    add('line',{x1:dp.tx,y1:py-arm,x2:dp.tx,y2:py+arm,class:'datum-inner'});
  }

  const r=Math.max(1.15,Math.min(3.25,planView.w/95));
  const labelSize=Math.max(1.8,Math.min(4,planView.w/62));
  const labelMode=$('labelMode')?.value||'id';
  points.map(transformPoint).forEach((p,i)=>{
    const y=invert?-p.ty:p.ty;
    const g=add('g',{'data-index':i,'class':'plan-point-group'+(i===planSelected?' selected':'')});
    const color=planColor(p.type);
    const kind=planSymbolKind(p.type);
    drawPlanSymbol(add,g,kind,p.tx,y,r,color);

    // Larger invisible hit target stays above the vector symbol.
    add('circle',{
      cx:p.tx,cy:y,r:r*2.15,
      fill:'transparent',stroke:'transparent',
      'pointer-events':'all',
      class:'point-hit',
      'data-index':i
    },g);

    if(i===planSelected){
      add('circle',{cx:p.tx,cy:y,r:r*1.72,class:'selected-ring'},g);
    }

    if(labelMode!=='none'){
      const txt=add('text',{
        x:p.tx+r*1.45,
        y:y+r*.32,
        class:'point-label',
        'font-size':labelSize,
        fill:'#111'
      },g);
      txt.textContent=labelMode==='idtype'&&p.type?`${p.id} · ${p.type}`:p.id;
    }
  });
}
function showPointReadout(p){
  if(!p)return;
  $('detailPointId').textContent=p.id||'Point';
  $('detailType').textContent=p.type||'—';
  $('detailX').textContent=feetInches(p.x,parseFloat($('precision').value));
  $('detailY').textContent=feetInches(p.y,parseFloat($('precision').value));
  $('detailLoad').textContent=Number.isFinite(Number(p.load)) ? `${Number(p.load).toLocaleString()} lb` : '—';
  $('detailTrim').textContent=p.trim||'—';
  $('detailCable').textContent=p.cable||'—';

  const card=$('pointDetailCard');
  card.classList.add('visible');
  card.scrollTop=0;
}
function zoomPlan(factor,cx=null,cy=null){
  const svg=$('planSvg'),rect=svg.getBoundingClientRect();
  const px=cx===null?.5:(cx-rect.left)/rect.width,py=cy===null?.5:(cy-rect.top)/rect.height;
  const nw=planView.w*factor,nh=planView.h*factor;
  planView.x+=(planView.w-nw)*px;
  planView.y+=(planView.h-nh)*($('invertPlanY').checked?1-py:py);
  planView.w=nw;planView.h=nh;renderPlan();
}




function xmlEscape(value){
  return String(value??'').replace(/[<>&'"]/g,c=>({
    '<':'&lt;','>':'&gt;','&':'&amp;',"'":'&apos;','"':'&quot;'
  }[c]));
}
function svgText(x,y,text,size=10,weight=400,anchor='middle',extra=''){
  const scaled=(Number(size)||10)*printScale();
  const family=xmlEscape(printFontFamily());
  const resolvedWeight=printWeightValue(weight);
  return `<text x="${x}" y="${y}" text-anchor="${anchor}" font-family="${family}" font-size="${scaled.toFixed(2)}" font-weight="${resolvedWeight}" ${extra}>${xmlEscape(text)}</text>`;
}
function svgFittedText(x,y,text,maxWidth,size=10,weight=400,anchor='middle',extra=''){
  const scaled=(Number(size)||10)*printScale();
  const family=xmlEscape(printFontFamily());
  const resolvedWeight=printWeightValue(weight);
  const value=String(text??'');
  // Conservative Helvetica-style width estimate. When it would exceed the
  // available lane, SVG textLength compresses spacing/glyphs just enough to fit.
  const estimated=Math.max(1,value.length*scaled*.61);
  const fitAttrs=estimated>maxWidth
    ? ` textLength="${Math.max(1,maxWidth).toFixed(2)}" lengthAdjust="spacingAndGlyphs"`
    : '';
  return `<text x="${x}" y="${y}" text-anchor="${anchor}" font-family="${family}" font-size="${scaled.toFixed(2)}" font-weight="${resolvedWeight}"${fitAttrs} ${extra}>${xmlEscape(value)}</text>`;
}
function buildFixedGridRows(){
  const groups=groupRows();
  const step=parseFloat($('precision').value);
  const origin=parseFloat($('originY').value)||0;
  const labels=orientationLabels();
  const zeroTol=Math.max(.0001,parseFloat($('tolerance').value||0)/12);
  const cellsPerSide=5;

  return groups.map(g=>{
    const left=g.points
      .filter(p=>p.tx < -zeroTol)
      .sort((a,b)=>Math.abs(a.tx)-Math.abs(b.tx));
    const center=g.points
      .filter(p=>Math.abs(p.tx)<=zeroTol)
      .sort((a,b)=>String(a.id).localeCompare(String(b.id)));
    const right=g.points
      .filter(p=>p.tx > zeroTol)
      .sort((a,b)=>Math.abs(a.tx)-Math.abs(b.tx));

    const levels=Math.max(
      1,
      Math.ceil(left.length/cellsPerSide),
      center.length,
      Math.ceil(right.length/cellsPerSide)
    );

    const leftLevels=[];
    const centerLevels=[];
    const rightLevels=[];
    for(let level=0;level<levels;level++){
      leftLevels.push(left.slice(level*cellsPerSide,(level+1)*cellsPerSide));
      centerLevels.push(center[level]||null);
      rightLevels.push(right.slice(level*cellsPerSide,(level+1)*cellsPerSide));
    }

    const rawRel=g.y-origin;
    const isZero=Math.abs(rawRel)<=zeroTol;
    const rel=isZero?0:rawRel;
    return {
      step,
      rel,
      dir:rel>=0?labels.positive:labels.negative,
      isZero,
      levels,
      leftLevels,
      centerLevels,
      rightLevels
    };
  });
}
function paginateFixedRows(rows,maxLevels){
  const pages=[];
  let page=[];
  let used=0;

  rows.forEach(row=>{
    if(page.length && used+row.levels>maxLevels){
      pages.push(page);
      page=[];
      used=0;
    }
    page.push(row);
    used+=row.levels;
  });
  if(page.length)pages.push(page);
  return pages;
}
let printClipCounter=0;
function printRigSymbolSvg(type,cx,cy,size){
  const kind=planSymbolKind(type);
  const color=planColor(type);
  const half=size/2;
  const stroke=1.35;
  const common=`fill="#fff" stroke="${color}" stroke-width="${stroke}" stroke-linejoin="miter"`;

  if(kind==='one'){
    return `<circle cx="${cx}" cy="${cy}" r="${half}" ${common}/>
      <line x1="${cx}" y1="${cy-half}" x2="${cx}" y2="${cy+half}" stroke="${color}" stroke-width="${stroke}"/>
      <line x1="${cx-half}" y1="${cy}" x2="${cx+half}" y2="${cy}" stroke="${color}" stroke-width="${stroke}"/>`;
  }
  if(kind==='half'){
    return `<polygon points="${cx},${cy-half-1} ${cx-half},${cy+half} ${cx+half},${cy+half}" ${common}/>
      <line x1="${cx}" y1="${cy-half}" x2="${cx}" y2="${cy+half}" stroke="${color}" stroke-width="${stroke}"/>
      <line x1="${cx-half*.55}" y1="${cy}" x2="${cx+half*.55}" y2="${cy}" stroke="${color}" stroke-width="${stroke}"/>`;
  }
  if(kind==='quarter'){
    return `<polygon points="${cx},${cy-half-1} ${cx+half+1},${cy} ${cx},${cy+half+1} ${cx-half-1},${cy}" ${common}/>
      <line x1="${cx}" y1="${cy-half}" x2="${cx}" y2="${cy+half}" stroke="${color}" stroke-width="${stroke}"/>
      <line x1="${cx-half}" y1="${cy}" x2="${cx+half}" y2="${cy}" stroke="${color}" stroke-width="${stroke}"/>`;
  }
  if(kind==='two'){
    return `<rect x="${cx-half}" y="${cy-half}" width="${size}" height="${size}" ${common}/>
      <line x1="${cx}" y1="${cy-half}" x2="${cx}" y2="${cy+half}" stroke="${color}" stroke-width="${stroke}"/>
      <line x1="${cx-half}" y1="${cy}" x2="${cx+half}" y2="${cy}" stroke="${color}" stroke-width="${stroke}"/>`;
  }

  return svgText(cx,cy+3,symbolFor(type),10,700,'middle',`fill="${color}"`);
}

function pointTextSvg(point,x,y,w,h,step){
  if(!point)return '';

  const measurement=feetInches(
    Math.abs(Number.isFinite(point.tx)?point.tx:point.x),
    step
  );
  const showCable=$('showCable')?.checked && point.cable;

  const MEASUREMENT_FONT=11.2;
  const POINT_ID_FONT=10.4;
  const CABLE_FONT=7.0;

  const measureY=y+(showCable?h*.31:h*.40);
  const idY=y+(showCable?h*.62:h*.74);
  const cableY=y+h*.87;

  const preset=printPreset();
  const iconSize=Math.min(preset.icon,h*.30);
  const symbolLane=Math.max(18,iconSize+preset.gap+4);
  const iconX=x+symbolLane/2;
  const textLeft=x+symbolLane;
  const textWidth=Math.max(8,w-symbolLane-5);
  const textCenter=textLeft+textWidth/2;

  // Clip every point to its own cell. This is a hard guarantee that no symbol,
  // measurement, ID, or cable label can bleed across a grid line.
  const clipId=`print-cell-${++printClipCounter}`;
  let out=`<defs><clipPath id="${clipId}"><rect x="${x+1}" y="${y+1}" width="${Math.max(1,w-2)}" height="${Math.max(1,h-2)}"/></clipPath></defs><g clip-path="url(#${clipId})">`;
  out+=printRigSymbolSvg(point.type,iconX,measureY-3,iconSize);
  out+=svgFittedText(textCenter,measureY,measurement,textWidth,MEASUREMENT_FONT,700);
  out+=svgFittedText(textCenter,idY,point.id,textWidth,POINT_ID_FONT,500);

  if(showCable){
    out+=svgFittedText(
      textCenter,
      cableY,
      `Cable: ${point.cable}`,
      textWidth,
      CABLE_FONT,
      400,
      'middle',
      'font-style="italic" fill="#444"'
    );
  }
  out+='</g>';
  return out;
}
function drawSideLevel(levelPoints,side,levelTop,levelBottom,centerX,centerW,colW,margin,step){
  const cells=5;
  let out='';
  const occupied=[];

  if(side==='left'){
    // Nearest point belongs in the cell touching center.
    // Render the chunk reversed into the right-most occupied cells.
    const count=levelPoints.length;
    levelPoints.forEach((point,index)=>{
      const col=(cells-1)-index;
      occupied.push(col);
      const x=margin+col*colW;
      out+=pointTextSvg(point,x,levelTop,colW,levelBottom-levelTop,step);
    });
  }else{
    levelPoints.forEach((point,index)=>{
      const col=index;
      occupied.push(col);
      const x=centerX+centerW+col*colW;
      out+=pointTextSvg(point,x,levelTop,colW,levelBottom-levelTop,step);
    });
  }

  if(!occupied.length)return out;

  // Draw each vertical boundary exactly once.
  const boundaries=new Set();
  occupied.forEach(col=>{
    if(side==='left'){
      boundaries.add(margin+col*colW);
      boundaries.add(margin+(col+1)*colW);
    }else{
      boundaries.add(centerX+centerW+col*colW);
      boundaries.add(centerX+centerW+(col+1)*colW);
    }
  });

  Array.from(boundaries).sort((a,b)=>a-b).forEach(x=>{
    out+=`<line x1="${x}" y1="${levelTop}" x2="${x}" y2="${levelBottom}" stroke="#000" stroke-width="1.45" shape-rendering="crispEdges"/>`;
  });

  return out;
}
function renderPrintPages(){
  printClipCounter=0;
  const host=$('printPages');
  if(!host)return;
  host.innerHTML='';

  const logicalRows=buildFixedGridRows();
  if(!logicalRows.length)return;

  const PAGE_W=816;
  const PAGE_H=1056;
  const MARGIN=26;
  const HEADER_H=72;
  const FOOTER_H=36;
  const CONTENT_TOP=HEADER_H+3;
  const CONTENT_BOTTOM=PAGE_H-FOOTER_H-4;

  const CENTER_W=76;
  const CENTER_X=(PAGE_W-CENTER_W)/2;
  const SIDE_W=CENTER_X-MARGIN;
  const COL_W=SIDE_W/5;

  const preset=printPreset();
  const maxLevels=Math.max(10,preset.maxLevels-($('showCable')?.checked?3:0));
  const pages=paginateFixedRows(logicalRows,maxLevels);
  const pageCount=pages.length;
  const slotH=(CONTENT_BOTTOM-CONTENT_TOP)/maxLevels;

  const totalLoad=points.reduce((sum,p)=>sum+(Number(p.load)||0),0);

  pages.forEach((pageRows,pageIndex)=>{
    let svg=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${PAGE_W} ${PAGE_H}">`;
    svg+=`<rect width="${PAGE_W}" height="${PAGE_H}" fill="#fff"/>`;

    // Header
    svg+=svgText(MARGIN,24,$('projectName').value||'UNTITLED MARKOUT',18,700,'start');
    svg+=svgText(MARGIN,39,`Export Date: ${fmtDate()}`,7.2,400,'start');
    svg+=svgText(MARGIN,50,`Point Count: ${points.length}`,7.2,400,'start');
    svg+=svgText(MARGIN,61,`Total Load: ${totalLoad?Math.round(totalLoad).toLocaleString()+' lb':'--- lb'}`,7.2,400,'start');
    const printLogoW=154, printLogoH=44;
    svg+=`<image href="${PRINT_HEADER_LOGO}" x="${PAGE_W-MARGIN-printLogoW}" y="14" width="${printLogoW}" height="${printLogoH}" preserveAspectRatio="xMidYMid meet"/>`;
    svg+=`<line x1="${MARGIN}" y1="${HEADER_H}" x2="${PAGE_W-MARGIN}" y2="${HEADER_H}" stroke="#000" stroke-width="1.45" shape-rendering="crispEdges"/>`;

    let levelCursor=0;

    pageRows.forEach(row=>{
      const rowTop=CONTENT_TOP+levelCursor*slotH;
      const rowBottom=rowTop+row.levels*slotH;
      const centerFill=row.isZero?'#58d62e':'#e8e8e8';

      // Full horizontal top and bottom borders for the logical row.
      svg+=`<line x1="${MARGIN}" y1="${rowTop}" x2="${PAGE_W-MARGIN}" y2="${rowTop}" stroke="#000" stroke-width="1.45" shape-rendering="crispEdges"/>`;
      svg+=`<line x1="${MARGIN}" y1="${rowBottom}" x2="${PAGE_W-MARGIN}" y2="${rowBottom}" stroke="#000" stroke-width="1.45" shape-rendering="crispEdges"/>`;

      for(let level=0;level<row.levels;level++){
        const levelTop=rowTop+level*slotH;
        const levelBottom=levelTop+slotH;

        // Internal divider crosses left/right halves only.
        if(level>0){
          svg+=`<line x1="${MARGIN}" y1="${levelTop}" x2="${CENTER_X}" y2="${levelTop}" stroke="#000" stroke-width="1.45" shape-rendering="crispEdges"/>`;
          svg+=`<line x1="${CENTER_X+CENTER_W}" y1="${levelTop}" x2="${PAGE_W-MARGIN}" y2="${levelTop}" stroke="#000" stroke-width="1.45" shape-rendering="crispEdges"/>`;
        }

        svg+=drawSideLevel(
          row.leftLevels[level],
          'left',
          levelTop,
          levelBottom,
          CENTER_X,
          CENTER_W,
          COL_W,
          MARGIN,
          row.step
        );
        svg+=drawSideLevel(
          row.rightLevels[level],
          'right',
          levelTop,
          levelBottom,
          CENTER_X,
          CENTER_W,
          COL_W,
          MARGIN,
          row.step
        );
      }

      // Paint the center column last so no side-point text can cross into it.
      svg+=`<rect x="${CENTER_X}" y="${rowTop}" width="${CENTER_W}" height="${rowBottom-rowTop}" fill="${centerFill}"/>`;
      svg+=`<line x1="${CENTER_X}" y1="${rowTop}" x2="${CENTER_X}" y2="${rowBottom}" stroke="#000" stroke-width="2.2" shape-rendering="crispEdges"/>`;
      svg+=`<line x1="${CENTER_X+CENTER_W}" y1="${rowTop}" x2="${CENTER_X+CENTER_W}" y2="${rowBottom}" stroke="#000" stroke-width="2.2" shape-rendering="crispEdges"/>`;

      // X = 0 points belong in the center column rather than being pushed right.
      // Keep the row's Y direction/distance as a compact header in the first level.
      for(let level=0;level<row.levels;level++){
        const levelTop=rowTop+level*slotH;
        const levelBottom=levelTop+slotH;
        if(level>0){
          svg+=`<line x1="${CENTER_X}" y1="${levelTop}" x2="${CENTER_X+CENTER_W}" y2="${levelTop}" stroke="#000" stroke-width="1.1" shape-rendering="crispEdges"/>`;
        }
        const centerPoint=row.centerLevels?.[level]||null;
        if(level===0){
          svg+=svgText(CENTER_X+CENTER_W/2,levelTop+9,row.isZero?'CENTER':row.dir,6.8,700);
          svg+=svgText(CENTER_X+CENTER_W/2,levelTop+20,feetInches(Math.abs(row.rel),row.step),12.5,700);
        }
        if(centerPoint){
          const measureY=levelTop+(level===0?31:18);
          const idY=Math.min(levelBottom-4,measureY+11);
          svg+=printRigSymbolSvg(centerPoint.type,CENTER_X+13,measureY-3,10);
          svg+=svgFittedText(CENTER_X+CENTER_W/2+7,measureY,`0' - 0"`,CENTER_W-27,8.2,700);
          svg+=svgFittedText(CENTER_X+CENTER_W/2,idY,centerPoint.id,CENTER_W-8,7.5,500);
        }
      }

      levelCursor+=row.levels;
    });

    // Footer: branded app icon, project metadata, and a scannable link to elevaterig.com.
    const footerY=PAGE_H-FOOTER_H;
    svg+=`<line x1="${MARGIN}" y1="${footerY}" x2="${PAGE_W-MARGIN}" y2="${footerY}" stroke="#000" stroke-width="1.1" shape-rendering="crispEdges"/>`;

    const footerIconX=MARGIN, footerIconY=footerY+5, footerIconSize=26;
    svg+=`<image href="${PRINT_BRAND_ICON}" x="${footerIconX}" y="${footerIconY}" width="${footerIconSize}" height="${footerIconSize}" preserveAspectRatio="xMidYMid meet"/>`;
    svg+=svgText(MARGIN+34,footerY+13,`Created with Elevate Layout · v${APP_VERSION}`,7.6,700,'start','fill="#333"');
    svg+=svgText(MARGIN+34,footerY+25,`Project: ${$('projectName').value||''}`,7.1,400,'start','fill="#555"');

    const qrSize=28, qrX=PAGE_W-MARGIN-qrSize, qrY=footerY+4;
    svg+=`<image href="${ELEVATERIG_QR}" x="${qrX}" y="${qrY}" width="${qrSize}" height="${qrSize}" preserveAspectRatio="xMidYMid meet"/>`;
    svg+=svgText(qrX-7,footerY+12,'SCAN TO VISIT',6.5,700,'end','fill="#333"');
    svg+=svgText(qrX-7,footerY+23,'elevaterig.com',7.1,500,'end','fill="#555"');

    const pageMetaX=qrX-116;
    svg+=svgText(pageMetaX,footerY+12,`Page ${pageIndex+1} of ${pageCount}`,8.4,700,'end');
    svg+=svgText(pageMetaX,footerY+24,fmtDate(),6.8,400,'end','fill="#666"');
    svg+='</svg>';

    const page=document.createElement('section');
    page.className='svg-print-page';
    page.innerHTML=svg;
    host.appendChild(page);
  });
}

function setStatus(name){
  $('status').innerHTML=`<strong>✓ ${points.length} points imported</strong><br>${escapeHTML(name)}<br>Point IDs and coordinates detected automatically.`;
}
async function loadText(text,name){
  try{
    points=normalize(parseCSV(text));
    if(!points.length)throw new Error('No valid point rows found. Required: a point/hoist ID plus X and Y in decimal feet or feet-and-inches.');
    const incoming=String(name||'');
    const isDifferent=incoming!==currentSourceFile;
    currentSourceFile=incoming;
    updateSelectedFileName(incoming);
    if(isDifferent || !$('projectName').value || $('projectName').value==='NEW MARKOUT'){
      $('projectName').value=cleanedFileTitle(incoming)||'NEW MARKOUT';
      lastAutoTitleFile=incoming;
      projectTitleCustomized=false;
    }
    setStatus(name);render();
  }catch(e){$('status').textContent='Import error: '+e.message}
}
function workbookSheetScore(sheet){
  try{
    const rows=XLSX.utils.sheet_to_json(sheet,{header:1,defval:'',raw:false,blankrows:false});
    const scan=rows.slice(0,30).map(r=>r.map(v=>String(v||'').trim().toLowerCase()));
    let best=0;
    for(const row of scan){
      const joined=row.join(' | ');
      let score=0;
      if(/hoist|point/.test(joined))score+=3;
      if(/dec\s*x|decimal\s*x|(^|\|)\s*x\s*(\||$)/.test(joined))score+=3;
      if(/dec\s*y|decimal\s*y|(^|\|)\s*y\s*(\||$)/.test(joined))score+=3;
      if(/hoist\s*type|type/.test(joined))score+=1;
      best=Math.max(best,score);
    }
    return best;
  }catch(_){return 0;}
}
function loadWorkbookFile(file){
  if(typeof XLSX==='undefined'){
    const status=$('status');
    if(status)status.innerHTML='<strong>Excel support did not load</strong><br>Reload while connected to the internet, then try the .xls/.xlsx file again.';
    return;
  }
  const reader=new FileReader();
  reader.onload=()=>{
    try{
      const workbook=XLSX.read(reader.result,{type:'array',cellDates:false,cellText:true,raw:false});
      if(!workbook.SheetNames.length)throw new Error('The workbook does not contain a readable worksheet.');
      const ranked=workbook.SheetNames.map((name,index)=>({name,index,score:workbookSheetScore(workbook.Sheets[name])}));
      ranked.sort((a,b)=>b.score-a.score||a.index-b.index);
      const selected=ranked[0];
      if(!selected || selected.score<6)throw new Error('No worksheet with recognizable Point/Hoist ID, X and Y columns was found.');
      const sheet=workbook.Sheets[selected.name];
      const csv=XLSX.utils.sheet_to_csv(sheet,{blankrows:false,FS:',',RS:'\n',strip:true});
      if(!csv.trim())throw new Error(`Worksheet “${selected.name}” is empty.`);
      loadText(csv,file.name);
      const status=$('status');
      if(status && workbook.SheetNames.length>1)status.innerHTML+=`<br>Worksheet: ${escapeHTML(selected.name)}`;
      if(window.matchMedia('(max-width:900px)').matches)setSidebarOpen(false);
    }catch(err){
      const status=$('status');
      if(status)status.innerHTML='<strong>Import error</strong><br>'+escapeHTML(String(err&&err.message?err.message:err));
    }
  };
  reader.onerror=()=>{const status=$('status');if(status)status.innerHTML='<strong>Import error</strong><br>Could not read this spreadsheet.';};
  reader.readAsArrayBuffer(file);
}
$('fileInput').addEventListener('change',e=>{
  const input=e.currentTarget;
  const f=input.files&&input.files[0];
  if(!f)return;
  if(/\.(xlsx?|xlsm)$/i.test(f.name)){loadWorkbookFile(f);return;}
  const reader=new FileReader();
  reader.onload=()=>{
    try{
      loadText(String(reader.result||''),f.name);
      if(window.matchMedia('(max-width:900px)').matches) setSidebarOpen(false);
    }catch(err){
      const status=$('status');
      if(status) status.innerHTML='<strong>Import error</strong><br>'+String(err&&err.message?err.message:err);
    }finally{ /* Keep the selected filename visible in the file picker after a successful import. */ }
  };
  reader.onerror=()=>{
    const status=$('status');
    if(status) status.innerHTML='<strong>Import error</strong><br>Chrome could not read this file. Try saving it to Downloads first.';
    input.value='';
  };
  reader.readAsText(f);
});
