// V19.1.1 Mac-friendly viewport interactions.
// Normal wheel / two-finger trackpad gestures retain native scrolling (pan).
// Command + wheel on macOS, or Control + wheel elsewhere, zooms around the cursor.
$('previewTab')?.addEventListener('wheel',event=>{
  const preview=$('previewTab');
  if(!preview?.classList.contains('active-view'))return;
  if(!(event.metaKey || event.ctrlKey))return;
  event.preventDefault();
  const delta=Math.abs(event.deltaY)>0?event.deltaY:event.deltaX;
  const intensity=Math.min(3,Math.max(.35,Math.abs(delta)/100));
  const base=1.10**intensity;
  const factor=delta<0?base:(1/base);
  zoomLayoutBy(factor,layoutPointerAnchor(event));
},{passive:false});

let layoutSpaceHeld=false;
let layoutPanState=null;

document.addEventListener('keydown',event=>{
  if(event.code!=='Space' || event.repeat)return;
  const target=event.target;
  if(target && /INPUT|TEXTAREA|SELECT|BUTTON/.test(target.tagName))return;
  layoutSpaceHeld=true;
  $('previewTab')?.classList.add('pan-ready');
  if($('previewTab')?.classList.contains('active-view'))event.preventDefault();
});

document.addEventListener('keyup',event=>{
  if(event.code!=='Space')return;
  layoutSpaceHeld=false;
  $('previewTab')?.classList.remove('pan-ready');
});

window.addEventListener('blur',()=>{
  layoutSpaceHeld=false;
  layoutPanState=null;
  $('previewTab')?.classList.remove('pan-ready','panning');
});

$('previewTab')?.addEventListener('pointerdown',event=>{
  const preview=$('previewTab');
  const shouldPan=event.button===1 || (event.button===0 && layoutSpaceHeld);
  if(!preview || !shouldPan)return;
  layoutPanState={
    pointerId:event.pointerId,
    clientX:event.clientX,
    clientY:event.clientY,
    scrollLeft:preview.scrollLeft,
    scrollTop:preview.scrollTop
  };
  preview.setPointerCapture?.(event.pointerId);
  preview.classList.add('panning');
  event.preventDefault();
});

$('previewTab')?.addEventListener('pointermove',event=>{
  const preview=$('previewTab');
  if(!preview || !layoutPanState || layoutPanState.pointerId!==event.pointerId)return;
  preview.scrollLeft=layoutPanState.scrollLeft-(event.clientX-layoutPanState.clientX);
  preview.scrollTop=layoutPanState.scrollTop-(event.clientY-layoutPanState.clientY);
  event.preventDefault();
});

function endLayoutPan(event){
  const preview=$('previewTab');
  if(!layoutPanState || (event && layoutPanState.pointerId!==event.pointerId))return;
  try{preview?.releasePointerCapture?.(layoutPanState.pointerId)}catch(_error){}
  layoutPanState=null;
  preview?.classList.remove('panning');
}
$('previewTab')?.addEventListener('pointerup',endLayoutPan);
$('previewTab')?.addEventListener('pointercancel',endLayoutPan);

