let planPointerStartGroup=null;

$('planSvg').addEventListener('pointerdown',e=>{
  planDragging=true;
  planMoved=false;
  planPointerStartGroup=e.target.closest?.('.plan-point-group[data-index]')||null;
  $('planSvg').classList.add('dragging');
  $('planSvg').setPointerCapture(e.pointerId);
  planDragStart={
    x:e.clientX,
    y:e.clientY,
    vx:planView.x,
    vy:planView.y
  };
});

$('planSvg').addEventListener('pointermove',e=>{
  if(!planDragging)return;

  if(Math.hypot(
    e.clientX-planDragStart.x,
    e.clientY-planDragStart.y
  )<5)return;

  planMoved=true;
  planPointerStartGroup=null;

  const r=$('planSvg').getBoundingClientRect();
  planView.x=planDragStart.vx-(e.clientX-planDragStart.x)/r.width*planView.w;

  const dy=(e.clientY-planDragStart.y)/r.height*planView.h;
  planView.y=planDragStart.vy+($('invertPlanY').checked?dy:-dy);
  renderPlan();
});

function endPlanPointer(e){
  if(!planDragging)return;

  const svg=$('planSvg');
  try{
    if(svg.hasPointerCapture(e.pointerId)){
      svg.releasePointerCapture(e.pointerId);
    }
  }catch(_){}

  svg.classList.remove('dragging');
  planDragging=false;

  if(!planMoved){
    // Prefer the point that received pointerdown.
    // Fall back to the element physically under the pointer after capture ends.
    const releasedTarget=document.elementFromPoint(e.clientX,e.clientY);
    const group=
      planPointerStartGroup ||
      releasedTarget?.closest?.('.plan-point-group[data-index]');

    if(group){
      const index=Number(group.dataset.index);
      if(Number.isInteger(index) && points[index]){
        planSelected=index;
        showPointReadout(points[index]);
        renderPlan();
      }
    }
  }

  planPointerStartGroup=null;
  planMoved=false;
}

$('planSvg').addEventListener('pointerup',endPlanPointer);
$('planSvg').addEventListener('pointercancel',e=>{
  planDragging=false;
  planMoved=false;
  planPointerStartGroup=null;
  $('planSvg').classList.remove('dragging');
});

render();






(function setupPointCardDrag(){
  const card=$('pointDetailCard');
  const handle=$('detailPointId');
  const close=$('pointDetailClose');
  const plan=$('planTab');
  if(!card || !handle || !plan)return;

  let dragging=false;
  let offsetX=0;
  let offsetY=0;

  function keepInside(left,top){
    const panel=plan.getBoundingClientRect();
    const box=card.getBoundingClientRect();
    return {
      left:Math.max(0,Math.min(left,panel.width-box.width)),
      top:Math.max(0,Math.min(top,panel.height-box.height))
    };
  }

  function beginDrag(clientX,clientY){
    const panel=plan.getBoundingClientRect();
    const box=card.getBoundingClientRect();

    card.classList.add('user-positioned','dragging');
    card.style.setProperty('right','auto','important');
    card.style.setProperty('bottom','auto','important');
    card.style.setProperty('left',`${box.left-panel.left}px`,'important');
    card.style.setProperty('top',`${box.top-panel.top}px`,'important');

    offsetX=clientX-box.left;
    offsetY=clientY-box.top;
    dragging=true;
  }

  function moveDrag(clientX,clientY){
    if(!dragging)return;
    const panel=plan.getBoundingClientRect();
    const next=keepInside(
      clientX-panel.left-offsetX,
      clientY-panel.top-offsetY
    );
    card.style.setProperty('left',`${next.left}px`,'important');
    card.style.setProperty('top',`${next.top}px`,'important');
  }

  handle.addEventListener('mousedown',e=>{
    if(e.button!==0 || !card.classList.contains('visible'))return;
    beginDrag(e.clientX,e.clientY);
    e.preventDefault();
  });

  document.addEventListener('mousemove',e=>moveDrag(e.clientX,e.clientY));
  document.addEventListener('mouseup',()=>{
    dragging=false;
    card.classList.remove('dragging');
  });

  handle.addEventListener('touchstart',e=>{
    if(!card.classList.contains('visible') || !e.touches.length)return;
    beginDrag(e.touches[0].clientX,e.touches[0].clientY);
    e.preventDefault();
  },{passive:false});

  document.addEventListener('touchmove',e=>{
    if(!dragging || !e.touches.length)return;
    moveDrag(e.touches[0].clientX,e.touches[0].clientY);
    e.preventDefault();
  },{passive:false});

  document.addEventListener('touchend',()=>{
    dragging=false;
    card.classList.remove('dragging');
  });

  close?.addEventListener('click',()=>card.classList.remove('visible'));

  window.addEventListener('resize',()=>{
    if(!card.classList.contains('user-positioned'))return;
    const left=parseFloat(card.style.left)||0;
    const top=parseFloat(card.style.top)||0;
    const next=keepInside(left,top);
    card.style.setProperty('left',`${next.left}px`,'important');
    card.style.setProperty('top',`${next.top}px`,'important');
  });
})();

(function repairWorkspaceStructure(){
  const viewport=document.querySelector('.workspace-viewport');
  const preview=$('previewTab');
  const plan=$('planTab');
  const data=$('dataTab');

  if(!viewport || !preview || !plan || !data)return;

  // All application views must be siblings inside one right-side viewport.
  [preview,plan,data].forEach(view=>{
    if(view.parentElement!==viewport){
      viewport.appendChild(view);
    }
  });

  // Remove old positioning classes that can override the active workspace.
  plan.classList.remove('hidden');
  data.classList.remove('hidden');

  // Preserve only the currently active view.
  const activeButton=document.querySelector('.tab.active');
  const activeName=activeButton?.dataset.tab || 'preview';
  const activeMap={preview,plan,data};

  Object.entries(activeMap).forEach(([name,view])=>{
    view.classList.toggle('active-view',name===activeName);
  });

  // Always begin Point Data at the true upper-left.
  const dataScroll=$('dataScroll');
  if(dataScroll){
    dataScroll.scrollTop=0;
    dataScroll.scrollLeft=0;
  }
})();



// Elevate Layout V14 responsive toolbar and controls drawer.
(function initV13Toolbar(){
  const byId=id=>document.getElementById(id);
  const sidebar=byId('appSidebar');
  const backdrop=byId('sidebarBackdrop');
  const toggle=byId('sidebarToggle');

  const mobileQuery=window.matchMedia('(max-width:1100px), (hover:none) and (pointer:coarse)');
  const isMobile=()=>mobileQuery.matches;

  function syncMobileMode(){
    const mobile=isMobile();
    document.body.classList.toggle('mobile-ui',mobile);
    if(!mobile) setSidebarOpen(false);

    // Use the actual header + command bar height instead of a hard-coded Android value.
    const appbar=document.querySelector('.appbar');
    const toolbar=document.querySelector('.command-toolbar');
    const chromeHeight=(appbar?.getBoundingClientRect().height||0)+(toolbar?.getBoundingClientRect().height||0);
    document.documentElement.style.setProperty('--mobile-chrome-height',`${Math.round(chromeHeight)}px`);
  }

  window.setSidebarOpen=function(open){
    const active=Boolean(open&&isMobile());
    document.body.classList.toggle('sidebar-open',active);
    toggle?.setAttribute('aria-expanded',String(active));
    sidebar?.setAttribute('aria-hidden',String(!active&&isMobile()));
    backdrop?.setAttribute('aria-hidden',String(!active));
  };

  toggle?.addEventListener('click',event=>{
    event.preventDefault();
    event.stopPropagation();
    setSidebarOpen(!document.body.classList.contains('sidebar-open'));
  });
  backdrop?.addEventListener('click',()=>setSidebarOpen(false));
  document.addEventListener('keydown',event=>{if(event.key==='Escape')setSidebarOpen(false)});
  window.addEventListener('resize',syncMobileMode,{passive:true});
  window.addEventListener('orientationchange',()=>setTimeout(syncMobileMode,100),{passive:true});
  mobileQuery.addEventListener?.('change',syncMobileMode);

  byId('toolbarImport')?.addEventListener('click',()=>byId('fileInput')?.click());
  byId('toolbarSample')?.addEventListener('click',()=>byId('sampleBtn')?.click());
  byId('toolbarClear')?.addEventListener('click',()=>byId('clearBtn')?.click());
  byId('toolbarFit')?.addEventListener('click',()=>{
    const planButton=document.querySelector('.tab[data-tab="plan"]');
    if(planButton?.classList.contains('active')) byId('fitPlan')?.click();
    else setLayoutViewMode('fit-width');
  });
  byId('toolbarPrint')?.addEventListener('click',()=>byId('printBtn')?.click());

  document.querySelectorAll('.tab').forEach(button=>button.addEventListener('click',()=>{
    if(isMobile())setSidebarOpen(false);
  }));

  // Close after choosing a file so the drawing is immediately visible on Android.
  byId('fileInput')?.addEventListener('change',()=>{
    if(isMobile()) setTimeout(()=>setSidebarOpen(false),0);
  });

  syncMobileMode();
  setSidebarOpen(false);
})();;

initLayoutResizeObserver();
